('Nabla', 'nabla', 'AI clinical note-taking assistant for healthcare providers', 'Nabla is an AI ambient documentation tool for healthcare. It listens to provider-patient conversations and auto-generates clinical notes in SOAP format. Reduces documentation time by 70% according to studies. Integrates with major EHR systems. HIPAA compliant.', 'https://nabla.com', 'paid', '[{"plan":"Individual","price":"$99/provider/mo","features":["Unlimited consultations","SOAP notes","EHR integration"]},{"plan":"Enterprise","price":"Contact sales","features":["Team management","Analytics","Custom templates"]}]', 'intermediate', true, '{web,mobile}', '{"Ambient note generation","SOAP format","EHR integration","Voice recognition","Template customization","Real-time transcription","HIPAA compliant","Multilingual support"}', '{"Epic","Athenahealth","eClinicalWorks","Cerner"}', NULL, true),

('Sybill', 'sybill', 'AI that summarizes sales calls and generates CRM notes', 'Sybill records and transcribes sales calls, then generates CRM notes, email follow-ups, and behavioral analysis of buyer intent. Detects when prospects are engaged vs. disinterested based on verbal and nonverbal cues. Integrates with Salesforce, HubSpot, and Zoom.', 'https://sybill.ai', 'paid', '[{"plan":"Starter","price":"$49/user/mo","features":["Call recording","AI summaries","CRM sync"]},{"plan":"Pro","price":"$99/user/mo","features":["Behavioral analysis","Deal intelligence","Coaching"]}]', 'intermediate', false, '{web,plugin}', '{"Sales call transcription","AI CRM notes","Email follow-up generation","Buyer intent analysis","Deal health scoring","Coaching insights","Zoom integration","CRM sync"}', '{"Salesforce","HubSpot","Zoom","Gong","Outreach"}', NULL, true);
